dev.off()

#Plot pink
melted_pink <- melt(transposed_pink, id.vars = "X", variable.name = "gene.ID", value.name = "expression" )
head(melted_pink)

melted_pink$expression <- as.numeric(melted_pink$expression)

agg_pink <- aggregate(
