#Pulling annotation information using module lists to identify specific genes in each module 

#Read in pairwise annotation file 
evlv_ann <- read.csv("merge_all.csv", stringsAsFactors = FALSE, header = TRUE, sep = ",")

#Read in whole transcriptome annotation files 
human_ann <- read.csv("swissprot_human_whole_trxm.csv", stringsAsFactors = FALSE, header = TRUE, sep = ",")

whole_ann <- read.csv("swissprot_all_whole_trxm.csv", stringsAsFactors = FALSE, header = TRUE, sep = ",")

#Filter annotated gene ids from module list
#Green
evlv_ann_green <- filter(evlv_ann, evlv_ann$genes %in% green$genes)

human_green <- filter(human_ann, human_ann$genes %in% green$genes)

all_green <- filter(whole_ann, whole_ann$genes %in% green$genes)

#LightCyan
evlv_lightcyan <- filter(evlv_ann, evlv_ann$genes %in% lightcyan$genes)

human_lightcyan <- filter(human_ann, human_ann$genes %in% lightcyan$genes)

all_lightcyan <- filter(whole_ann, whole_ann$genes %in% lightcyan$genes)

#Pink
evlv_pink <- filter(evlv_ann, evlv_ann$genes %in% pink$genes)

human_pink <- filter(human_ann, human_ann$genes %in% pink$genes)

all_pink <- filter(whole_ann, whole_ann$genes %in% pink$genes)

